const recs = (n) => $(n).all().flatMap((it) => (it.json && it.json.records) || []);
const proyectos = recs('Leer Proyectos');
const voces = recs('Leer Voces');
const referentes = recs('Leer Referentes');
const _nrm = (s) => (s||'').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim();
const cfg0 = $('Config').first().json;
const AJUSTE_MAP = { 'peso de vistas':'peso_views', 'peso de likes':'peso_likes', 'peso de interaccion':'peso_eng', 'peso de relevancia':'peso_relevancia', 'bonus idioma extranjero':'boost_idioma', 'seguidores para marcar viral':'umbral_viral', 'minimo de vistas':'min_views', 'minimo de likes':'min_likes', 'relevancia minima':'min_relevancia', 'candidatos por corrida':'top_n', 'dias de recencia':'dias_recencia', 'resultados por cuenta de referente':'resultados_referente', 'buscar por referentes en instagram':'buscar_referente_ig', 'buscar por referentes en tiktok':'buscar_referente_tiktok' };
const ajustes = {};
recs('Leer Ajustes').forEach(a => { const f = a.fields || {}; const key = AJUSTE_MAP[_nrm(f.clave)]; if (key && f.valor !== undefined && f.valor !== null && f.valor !== '') ajustes[key] = Number(f.valor); });

// Knobs de ejecucion GLOBALES (ADR-016): ajustes (equipo) > Config (default). Topes dev-only en Config.
const pick = (k, d) => (ajustes[k] != null ? ajustes[k] : (cfg0[k] != null ? Number(cfg0[k]) : d));
const dias_recencia = Number(pick('dias_recencia', 7));
const top_n = Number(pick('top_n', 100));
const cap_rr = Number(cfg0.cap_resultados_referente || 0);
const rr_raw = Number(pick('resultados_referente', 20));
const resultados_referente = cap_rr > 0 ? Math.min(rr_raw, cap_rr) : rr_raw; // cap max (ADR-016)
const cap_top_n = Number(cfg0.cap_top_n || 0);
// Toggles de eje (ADR-017): ajustes (equipo) > Config. Default ON. Referentes en ambas plataformas — unico eje de descubrimiento (ADR-019).
const BUSCAR_REF_IG = Number(pick('buscar_referente_ig', 1)) > 0;
const BUSCAR_REF_TT = Number(pick('buscar_referente_tiktok', 1)) > 0;

// 'Leer Voces' ya viene filtrado por {activo} (C.2): lo que no está acá, está apagado.
const vozById = {};
const vozCritById = {};
voces.forEach(v => { const vf = v.fields || {}; vozById[v.id] = vf.nombre || ''; vozCritById[v.id] = (vf.criterios_relevancia || '').toString().trim(); });

const projects = {};
proyectos.forEach(p => {
  const f = p.fields || {};
  const vozId = Array.isArray(f.voz_default) && f.voz_default[0] ? f.voz_default[0] : null;
  // Voces.activo (C.2): un proyecto activo cuya VOZ esta apagada NO corre. La voz es la espina dorsal:
  // se prende/apaga como unidad y arrastra a sus proyectos. Un proyecto SIN voz no esta gateado (corre).
  if (vozId && !vozById.hasOwnProperty(vozId)) { console.log('[Plan] proyecto salteado (voz apagada): ' + (f.nombre || p.id)); return; }
  // Anomalia de dato: voz_default es multi-link y el contrato dice 1 proyecto = 1 voz. Si hay mas de
  // una, el motor usa la PRIMERA (criterios, nombre y este gate) y las demas se ignoran. Se avisa en
  // vez de tragarselo — si esto aparece, hay que limpiar el dato o cambiar el modelo (no el codigo).
  if (Array.isArray(f.voz_default) && f.voz_default.length > 1) console.log('[Plan] ⚠️ ' + (f.nombre || p.id) + ' tiene ' + f.voz_default.length + ' voces linkeadas; se usa solo la primera. Limpiar voz_default.');
  // N por proyecto (ADR-024): el campo del proyecto manda; el global 'Candidatos por corrida' es el
  // default. Misma semantica en cron y on-demand. 0/vacio/no-numero => cae al global.
  const _nProy = Number(f.N);
  projects[p.id] = {
    id: p.id, nombre: f.nombre || '', n: (_nProy > 0 ? _nProy : top_n),
    voz_id: vozId, voz_nombre: vozId && vozById[vozId] ? vozById[vozId] : '',
    criterios: (f.criterios_relevancia || '').toString().trim(),
    criterios_aprendidos: (f.criterios_aprendidos || '').toString().trim(),
    voz_criterios: vozId && vozCritById[vozId] ? vozCritById[vozId] : '',
    ig_handles: [], tt_handles: []
  };
});
referentes.forEach(r => {
  const f = r.fields || {};
  const handle = String(f.handle || '').trim().replace(/^@/, '');
  if (!handle) return;
  const plat = String(f.plataforma || '').toLowerCase();
  (Array.isArray(f.proyecto) ? f.proyecto : []).forEach(proy => {
    if (!projects[proy]) return;
    if (plat.indexOf('insta') >= 0) projects[proy].ig_handles.push(handle);
    else if (plat.indexOf('tik') >= 0) projects[proy].tt_handles.push(handle);
  });
});

const ig_urls = []; const ig_owner_to_proj = {};
const tt_profiles = []; const tt_owner_to_proj = {};
Object.values(projects).forEach(p => {
  // Referente: IG por cuenta (directUrls), TikTok por perfil (profiles). Gateado por toggle (ADR-017).
  if (BUSCAR_REF_IG) p.ig_handles.forEach(h => { ig_urls.push('https://www.instagram.com/' + h + '/'); (ig_owner_to_proj[h.toLowerCase()] = ig_owner_to_proj[h.toLowerCase()] || []).push(p.id); });
  if (BUSCAR_REF_TT) p.tt_handles.forEach(h => { tt_profiles.push(h); (tt_owner_to_proj[h.toLowerCase()] = tt_owner_to_proj[h.toLowerCase()] || []).push(p.id); });
});

return [{ json: {
  projects, ig_urls: [...new Set(ig_urls)], tt_profiles: [...new Set(tt_profiles)],
  ig_owner_to_proj, tt_owner_to_proj, active_project_ids: Object.keys(projects),
  dias_recencia, resultados_referente, top_n, cap_top_n, ajustes
} }];

// #24: un item por referente IG -> el Apify IG Reels corre 1 vez por cuenta,
// cada llamada con su propio cupo (resultsLimit deja de ser global). Reparte equitativo.
const urls = ($('Armar plan de corrida').first().json.ig_urls) || [];
return urls.map(u => ({ json: { ig_url: u } }));

const item = $input.item.json;
// Solo reels/videos: IG trae fotos y carruseles que no se pueden transcribir; descartar lo que no sea video.
if (item.type && item.type !== 'Video') { return null; }
// Stub de Apify (llamada vacía devuelve {error:'no_items'}): sin id ni url -> descartar.
if (!(item.id || item.shortCode || item.shortcode) && !item.url) { return null; }
const seguidores = item.followersCount || item.ownerFollowersCount || (item.metaData && item.metaData.followersCount) || 0;
return { json: {
  plataforma: 'instagram',
  external_id: String(item.id || item.shortCode || item.shortcode || ''),
  username: item.ownerUsername || '',
  nombre: item.ownerFullName || '',
  seguidores,
  bio: item.biography || item.ownerBio || (item.metaData && item.metaData.biography) || '',
  descripcion: item.caption || '',
  likes: item.likesCount || 0,
  comentarios: item.commentsCount || 0,
  reproducciones: item.videoViewCount || item.videoPlayCount || item.igPlayCount || 0,
  url: item.url || '',
  video_url: item.url || '',
  thumbnail_url: item.displayUrl || '',
  hashtags: (item.hashtags || []).join(', '),
  duracion_video: item.videoDuration || 0,
  engagement_rate: seguidores > 0 ? (((item.likesCount || 0) + (item.commentsCount || 0)) / seguidores * 100).toFixed(2) : '0',
  fecha_publicacion: (function(){ var d = new Date(item.timestamp); return isNaN(d.getTime()) ? '' : d.toISOString().split('T')[0]; })()
} };

const item = $input.item.json;
// Stub de un eje vacío (TikTok-Perfil con 0 referentes devuelve {}): sin id ni url -> descartar.
if (!item.id && !item.webVideoUrl) { return null; }
const am = item.authorMeta || {};
const seguidores = am.fans || 0;
return { json: {
  plataforma: 'tiktok',
  idioma_nativo: (item.textLanguage && item.textLanguage !== 'un') ? String(item.textLanguage).toLowerCase().slice(0, 2) : '',
  external_id: String(item.id || ''),
  username: am.name || '',
  nombre: am.nickName || '',
  seguidores,
  bio: am.signature || '',
  descripcion: item.text || item.desc || '',
  likes: item.diggCount || 0,
  comentarios: item.commentCount || 0,
  reproducciones: item.playCount || 0,
  url: item.webVideoUrl || '',
  video_url: item.webVideoUrl || '',
  thumbnail_url: (item.videoMeta && item.videoMeta.coverUrl) || '',
  hashtags: (item.hashtags || []).map(function (h) { return h.name || h; }).join(', '),
  duracion_video: item.videoMeta ? (item.videoMeta.duration || 0) : 0,
  engagement_rate: seguidores > 0 ? (((item.diggCount || 0) + (item.commentCount || 0)) / seguidores * 100).toFixed(2) : '0',
  fecha_publicacion: item.createTimeISO ? item.createTimeISO.split('T')[0] : ''
} };

const plan = $('Armar plan de corrida').first().json;
const projects = plan.projects, ig_owner = plan.ig_owner_to_proj || {}, tt_owner = plan.tt_owner_to_proj || {};
const activeIds = plan.active_project_ids || [];
const DIAS = Number(plan.dias_recencia || 0); // recencia global (ADR-016)
const out = [];
for (const it of $input.all()) {
  const d = it.json;
  if (!d.url) continue;
  const u = String(d.username || '').toLowerCase().replace(/^@/, '');
  // Fan-out (ADR-013): un mismo video puede ser reclamado por varios proyectos activos a la vez
  // (referente compartido entre proyectos). Solo reclama el referente (ADR-019).
  const claims = {};
  const ownerList = (d.plataforma || '') === 'instagram' ? (ig_owner[u] || [])
                  : (d.plataforma || '') === 'tiktok' ? (tt_owner[u] || []) : [];
  ownerList.forEach(pid => { if (!(pid in claims)) claims[pid] = ''; });
  // fallback: si nada lo reclamo y hay UN solo proyecto activo, se lo lleva ese.
  let pids = Object.keys(claims);
  if (!pids.length && activeIds.length === 1) { claims[activeIds[0]] = ''; pids = [activeIds[0]]; }
  for (const proyId of pids) {
    const p = projects[proyId];
    if (!p) continue;
    // guardia de recencia (capa 2): descarta lo mas viejo que dias_recencia del proyecto.
    // 0 = sin limite. Si no hay fecha, se conserva (no se puede juzgar la edad).
    if (DIAS > 0 && d.fecha_publicacion) {
      const ts = Date.parse(d.fecha_publicacion);
      if (Number.isFinite(ts) && (Date.now() - ts) > DIAS * 86400000) continue;
    }
    out.push({ json: Object.assign({}, d, {
      proyecto_id: proyId, proyecto_nombre: p.nombre, voz_id: p.voz_id, voz_nombre: p.voz_nombre
    }) });
  }
}
return out;

// Pre-trim de relevancia (Haiku) — colador LAXO sobre el caption, ANTES de transcribir.
// Optimiza recall: descarta solo lo OBVIAMENTE off-topic. Fail-open (si Haiku falla, pasa todo).
// Caption pobre (sin texto real): pasa sin juicio -> lo juzga el gate con el transcript.
const KEY = '<ANTHROPIC_API_KEY>';
const plan = $('Armar plan de corrida').first().json || {};
const projects = plan.projects || {};
const items = $('Asignar proyecto+voz').all().map(i => i.json);

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });

const drop = new Set();
for (const pid in byProj) {
  const arr = byProj[pid];
  const p = projects[pid] || {};
  const critProy = (p.criterios || '').toString().trim();
  const critVoz = (p.voz_criterios || '').toString().trim();
  const criterios = [critProy, critVoz].filter(Boolean).join('\n').trim();
  const criteriosTxt = [critProy ? 'CRITERIOS DE TEMA (principal):\n' + critProy : '', critVoz ? 'AJUSTE DE VOZ (complementa, no manda):\n' + critVoz : ''].filter(Boolean).join('\n\n');
  if (!criterios) continue; // sin rúbrica no se juzga: no se descarta nada
  // Caption pobre = sin evidencia para juzgar (fix calidad run 07-09): pasa SIN juicio ->
  // lo juzga el gate con el transcript (la fuente siempre es curada: referente, ADR-019).
  const _senal = (d) => String(d.descripcion || '').replace(/https?:\/\/\S+/g, ' ').replace(/[#@]\S+/g, ' ').replace(/[^\p{L}\p{N}?!.,;: ]/gu, ' ').replace(/\s+/g, ' ').trim();
  const _judge = [];
  let _exentos = 0;
  for (const d of arr) {
    if (!String(d.external_id || '')) continue;
    if (_senal(d).length < 25) { _exentos++; continue; }
    _judge.push(d);
  }
  if (_exentos) console.log('[Pre-trim] captions pobres pid=' + pid + ': ' + _exentos + ' exentos (pasan al gate)');
  const lote = _judge.map(d => ({
    id: String(d.external_id || ''),
    texto: (String(d.descripcion || '') + ' ' + String(d.hashtags || '')).replace(/\s+/g, ' ').trim().slice(0, 500)
  })).filter(x => x.id);
  if (!lote.length) continue;
  const sys = 'Sos un filtro de relevancia LAXO. Te doy el tema de un proyecto, sus criterios (el TEMA manda; el AJUSTE DE VOZ solo complementa), y una lista de videos (id + texto del caption). Devolve UNICAMENTE un JSON {"descartar":[ids]} con los ids OBVIAMENTE fuera de tema. En la duda NO descartes (preferimos dejar pasar de mas). No expliques nada.';
  const usr = 'TEMA: ' + (p.nombre || '') + '\n' + criteriosTxt + '\n\nVIDEOS:\n' + JSON.stringify(lote);
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: 'claude-haiku-4-5', max_tokens: 1000, system: sys, messages: [{ role: 'user', content: usr }] },
      json: true,
      timeout: 30000
    });
    let txt = '';
    try { txt = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
    const m = String(txt).match(/\{[\s\S]*\}/);
    if (m) { const parsed = JSON.parse(m[0]); (parsed.descartar || []).forEach(id => drop.add(pid + '|' + String(id))); }
  } catch (e) { /* fail-open: no se descarta nada de este proyecto */ }
}

const _desc = [...drop];
console.log('[Pre-trim] descartados off-topic: ' + _desc.length + '/' + items.length + (_desc.length ? ' -> ' + _desc.join(', ') : ''));
const out = [];
for (const d of items) { if (!drop.has(String(d.proyecto_id) + '|' + String(d.external_id || ''))) out.push({ json: d }); }
return out;

const cfg = Object.assign({}, $('Config').first().json, ($('Armar plan de corrida').first().json.ajustes || {}));
const rows = (n) => { const a = $(n).all().map(i => i.json); if (a.length === 1 && Array.isArray(a[0])) return a[0]; return a; };
const items = $('Pre-trim relevancia').all().map(i => i.json);
const seen = new Set(rows('Leer procesados').map(r => r && String(r.external_id)).filter(Boolean));
const signal = {};
rows('Leer señal selección').forEach(r => { if (r && r.referente !== undefined) signal[(r.referente || '') + '|' + (r.idioma || '')] = Number(r.tasa_seleccion || 0); });

const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ', ' la ', ' los ', ' las ', ' que ', ' de ', ' para ', ' con ', ' una ', ' como ', ' pero ', ' esto '],
  en: [' the ', ' and ', ' you ', ' for ', ' with ', ' this ', ' that ', ' your ', ' are ', ' have ', ' what '],
  pt: [' uma ', ' voce ', ' nao ', ' isso ', ' mais ', ' como ', ' obrigado ', ' entao ', ' muito '],
  it: [' il ', ' che ', ' per ', ' una ', ' questo ', ' come ', ' sono ', ' non ', ' anche ', ' molto '],
  fr: [' les ', ' une ', ' pour ', ' avec ', ' vous ', ' est ', ' pas ', ' comme ', ' dans ', ' mais '],
  de: [' der ', ' die ', ' und ', ' ist ', ' nicht ', ' ein ', ' mit ', ' das ', ' ich ', ' auch '],
  nl: [' het ', ' een ', ' van ', ' ik ', ' niet ', ' met ', ' dat ', ' zijn ', ' voor ', ' ook ']
};
// scripts no-latinos: evidencia directa de NO-español (caen a 'ot' -> reciben boost)
const NONLATIN = /[\u3040-\u30ff\u4e00-\u9fff\uac00-\ud7af\u0400-\u04ff\u0600-\u06ff\u0590-\u05ff\u0900-\u097f\u0e00-\u0e7f\u0370-\u03ff]/;
const guessLang = (raw) => {
  const orig = (raw || '').toString();
  if (NONLATIN.test(orig)) return 'ot';
  const t = ' ' + norm(orig) + ' '; let best = '', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(w => { if (t.indexOf(w) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  if (bestN > 0) return best;
  // sin stopwords reconocidas: marcas fuertes de español -> es; si no, desconocido -> 'ot' (premia no-español)
  if (/[ñ¿¡áéíóú]/.test(orig.toLowerCase())) return 'es';
  return 'ot';
};
const pct = (arr, v) => { if (arr.length <= 1) return 1; let c = 0; for (const x of arr) if (x <= v) c++; return c / arr.length; };

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });
const out = [];
for (const pid in byProj) {
  const arr = byProj[pid];
  const views = arr.map(d => Number(d.reproducciones || 0));
  const likes = arr.map(d => Number(d.likes || 0));
  const engs = arr.map(d => parseFloat(d.engagement_rate) || 0);
  const scored = arr.map(d => {
    const v = Number(d.reproducciones || 0), l = Number(d.likes || 0), e = parseFloat(d.engagement_rate) || 0;
    const idioma = d.idioma_nativo || guessLang((d.descripcion || '') + ' ' + (d.bio || ''));
    const idiomaBoost = idioma !== 'es' ? Number(cfg.boost_idioma || 0.3) : 0;
    const sel = signal[(d.username || '') + '|' + idioma] || 0; // señal por referente (ADR-019)
    const base = Number(cfg.peso_views || 0.4) * pct(views, v) + Number(cfg.peso_likes || 0.4) * pct(likes, l) + Number(cfg.peso_eng || 0.2) * pct(engs, e);
    const heat = base * (1 + idiomaBoost) * (1 + sel);
    return Object.assign({}, d, {
      idioma_guess: idioma, heat_score: Math.round(heat * 10000) / 10000,
      viral_por_tamano: Number(d.seguidores || 0) > Number(cfg.umbral_viral || 700000)
    });
  });
  const MIN_V = Number(cfg.min_views || 0), MIN_L = Number(cfg.min_likes || 0);
  const fresh = scored.filter(d => !seen.has(String(d.external_id)) && Number(d.reproducciones || 0) >= MIN_V && Number(d.likes || 0) >= MIN_L);
  fresh.sort((a, b) => b.heat_score - a.heat_score);
  fresh.forEach(d => out.push({ json: d })); // ADR-016: sin corte por proyecto; se transcribe todo
}
// cap_top_n (dev-only): techo duro de transcripcion por corrida (protege backfill).
// ADR-016: cuenta VIDEOS DISTINTOS por heat, no filas (video,proyecto); el fan-out no consume cupo.
const CAP = Number($('Config').first().json.cap_top_n || 0);
if (CAP > 0) { out.sort((a, b) => (b.json.heat_score || 0) - (a.json.heat_score || 0)); const keepIds = new Set(); const capped = []; for (const it of out) { const id = String(it.json.external_id || ''); if (!id) { capped.push(it); continue; } if (!keepIds.has(id)) { if (keepIds.size >= CAP) continue; keepIds.add(id); } capped.push(it); } return capped; }
return out;

// Transcribir (Supadata) — dedup intra-corrida (ADR-016): cada external_id se transcribe UNA vez y
// el transcript se reparte a TODAS las copias (fan-out). external_id atado al item (#8). lang de
// Supadata primario; fallback adivina sobre el TRANSCRIPT (#7). Fail-open: si falla, transcripcion vacia.
const KEY = '<SUPADATA_API_KEY>';
const SLEEP_MS = 1000;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ',' la ',' que ',' de ',' para ',' con ',' una ',' como ',' pero ',' esto '],
  en: [' the ',' and ',' you ',' for ',' with ',' this ',' that ',' your ',' are ',' what '],
  pt: [' uma ',' voce ',' nao ',' isso ',' mais ',' como ',' entao ',' muito '],
  it: [' il ',' che ',' per ',' una ',' questo ',' come ',' sono ',' non ',' molto '],
  fr: [' les ',' une ',' pour ',' avec ',' vous ',' est ',' pas ',' comme ',' mais ']
};
const guessLang = (txt) => {
  const t = ' ' + norm(txt) + ' '; let best = '', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(p => { if (t.indexOf(p) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  return bestN === 0 ? '' : best;
};
const items = $input.all();
// 1) videos distintos por external_id (url de respaldo)
const order = []; const firstUrl = {};
for (const it of items) { const d = it.json; const id = String(d.external_id || d.url || ''); if (!id) continue; if (!(id in firstUrl)) { firstUrl[id] = d.video_url || d.url || ''; order.push(id); } }
console.log(`[Transcribir] ${items.length} items / ${order.length} videos distintos`);
// 2) transcribir cada distinto UNA vez
const cache = {}; const loopStart = Date.now();
// Presupuesto de tiempo (cierre 31): el watchdog del task runner (N8N_RUNNERS_TASK_TIMEOUT, 900s en
// el pod) mata el NODO ENTERO y el run muere sin entregar nada (pasó 3x el 07-10 con top_n≈100).
// Con presupuesto, el loop se corta ANTES y el resto pasa SIN transcript (fail-open: el gate juzga
// por caption y el candidato sale marcado SIN GUION). Dev-only en Config; 0 = sin presupuesto.
const BUDGET_MS = Math.max(0, Number($('Config').first().json.presupuesto_transcribir_s || 0)) * 1000;
for (let i = 0; i < order.length; i++) {
  if (BUDGET_MS && Date.now() - loopStart > BUDGET_MS) { console.log(`[Transcribir] PRESUPUESTO agotado (${Math.round(BUDGET_MS / 1000)}s): ${order.length - i} videos quedan sin transcript (fail-open)`); break; }
  const id = order[i]; const url = firstUrl[id];
  let txt = '', lang = '';
  const t0 = Date.now();
  console.log(`[Transcribir] Video ${i+1}/${order.length} — url: ${url}`);
  if (url) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://api.supadata.ai/v1/transcript?url=' + encodeURIComponent(url) + '&text=true&mode=auto',
        headers: { 'x-api-key': KEY }, json: true, timeout: 90000
      });
      txt = (typeof resp.content === 'string' && resp.content) || (typeof resp.text === 'string' && resp.text) || '';
      lang = String(resp.lang || resp.language || '').toLowerCase().slice(0, 2);
      console.log(`[Transcribir] Video ${i+1}/${order.length} — OK en ${Date.now()-t0}ms`);
    } catch (e) { console.log(`[Transcribir] Video ${i+1}/${order.length} — ERROR/TIMEOUT en ${Date.now()-t0}ms: ${e.message}`); }
    if (i < order.length - 1) await sleep(SLEEP_MS);
  }
  cache[id] = { txt: String(txt || '').trim().substring(0, 6000), lang };
}
console.log(`[Transcribir] Loop completo en ${Date.now()-loopStart}ms`);
// 3) repartir a TODAS las copias
const out = [];
for (const it of items) {
  const d = it.json; const id = String(d.external_id || d.url || '');
  const c = cache[id] || { txt: '', lang: '' };
  const idioma = c.lang || guessLang(c.txt) || d.idioma_guess || 'es';
  out.push({ json: Object.assign({}, d, { transcripcion: c.txt, idioma_detectado: idioma }) });
}
return out;

// Traducir (Claude Haiku) — reemplaza IF + Script-desde-transcripción + Claude HTTP + Merge(pos) + Parsear.
// Traduce literal al español SOLO si el original no está en español. external_id atado al item (#8).
// Dedup intra-corrida (cierre 31, espejo de Transcribir): cada video distinto se traduce UNA vez y el
// script se reparte a TODAS las copias del fan-out (antes se pagaba 1 llamada Haiku por copia).
// Fail-open: si la traducción falla o devuelve vacío, el script queda como el transcript original.
const KEY = '<ANTHROPIC_API_KEY>';
const SLEEP_MS = 1000; // throttle entre llamadas reales
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const SYS = 'Sos un traductor literal. Traduci el texto al espanol neutro de forma fiel y literal: sin reescribir, sin resumir, sin embellecer, sin agregar ni quitar nada; conserva el sentido y el orden. Devolve UNICAMENTE el texto traducido, sin comillas ni comentarios.';
const items = $input.all();
// 1) videos distintos que necesitan traducción (transcript no vacío y no-ES)
const order = []; const seen = new Set();
for (const it of items) {
  const d = it.json; const id = String(d.external_id || d.url || '');
  if (!id || seen.has(id)) continue;
  seen.add(id);
  const transcript = String(d.transcripcion || '');
  const idioma = d.idioma_detectado || d.idioma_guess || 'es';
  if (transcript && idioma !== 'es') order.push({ id, transcript });
}
console.log('[Traducir] ' + items.length + ' items / ' + order.length + ' videos distintos a traducir');
// 2) traducir cada distinto UNA vez
const cache = {};
for (let i = 0; i < order.length; i++) {
  const { id, transcript } = order[i];
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: 'claude-haiku-4-5', max_tokens: 2000, system: SYS, messages: [{ role: 'user', content: transcript.substring(0, 6000) }] },
      json: true, timeout: 60000
    });
    let tr = '';
    try { tr = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
    tr = String(tr || '').trim();
    if (tr) cache[id] = tr;
  } catch (e) { /* fail-open: esta copia queda con el transcript original */ }
  if (i < order.length - 1) await sleep(SLEEP_MS);
}
// 3) repartir a TODAS las copias
const out = [];
for (const it of items) {
  const d = it.json; const id = String(d.external_id || d.url || '');
  const transcript = String(d.transcripcion || '');
  const idioma = d.idioma_detectado || d.idioma_guess || 'es';
  out.push({ json: Object.assign({}, d, { script: (cache[id] || transcript), idioma }) });
}
return out;

// Gate de relevancia (Haiku) — jurado ESTRICTO sobre el transcript (precision). Llena CALIDAD (PLAN §2.4).
// Juzga relevancia/calidad contra criterios_relevancia (Proyecto ⊕ Voz) → {relevante, score, razon}.
// Dropea los relevante:false. Composite: heat = PESO·score_haiku + (1-PESO)·percentil(prescore métrico).
// Sin transcript: juzga el caption (descripcion) como fallback; si pasa, se marca [SIN TRANSCRIPT...].
// Fail-open: sin criterios o si Haiku falla, pasa todo y ordena por el prescore métrico.
const KEY = '<ANTHROPIC_API_KEY>';
const cfg = Object.assign({}, $('Config').first().json, ($('Armar plan de corrida').first().json.ajustes || {}));
const PESO = Number(cfg.peso_relevancia != null ? cfg.peso_relevancia : 0.7);
const MIN_REL = Number(cfg.min_relevancia || 0); // umbral duro: dropea score < MIN_REL (default 0)
// Descartes visibles (ADR-021, enmienda 2026-07-13): Haiku rechaza decisivo (bimodal, casi nada en
// [0.35,0.6]) → la banda fija nunca se poblaba. Ahora expone los TOP-K rechazos por score (los
// near-miss: los que estuvieron mas cerca de pasar = los mas probables falsos negativos). Knob dev-only.
const CAP_DESC = Number(cfg.cap_descartes != null ? cfg.cap_descartes : 10);
const _borderline = [];
const projects = ($('Armar plan de corrida').first().json || {}).projects || {};
const SLEEP_MS = 1000;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const pct = (arr, v) => { if (arr.length <= 1) return 1; let c = 0; for (const x of arr) if (x <= v) c++; return c / arr.length; };

const items = $input.all().map(i => i.json);
const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });

const out = [];
let first = true;
for (const pid in byProj) {
  const arr = byProj[pid];
  const p = projects[pid] || {};
  const critProy = (p.criterios || '').toString().trim();
  const critVoz = (p.voz_criterios || '').toString().trim();
  const critAprend = (p.criterios_aprendidos || '').toString().trim();
  const criterios = [critProy, critVoz, critAprend].filter(Boolean).join('\n').trim();
  const criteriosTxt = [critProy ? 'CRITERIOS DE TEMA (principal):\n' + critProy : '', critVoz ? 'AJUSTE DE VOZ (complementa, no manda):\n' + critVoz : '', critAprend ? 'PATRONES APRENDIDOS (de decisiones reales del equipo; guia, no ley):\n' + critAprend : ''].filter(Boolean).join('\n\n');
  const juicio = {}; // external_id → { relevante, score, razon }
  if (criterios) {
    const lote = arr.map(d => ({ id: String(d.external_id || ''), texto: (String(d.script || '').trim() || String(d.descripcion || '').trim()).replace(/\s+/g, ' ').trim().slice(0, 1500) })).filter(x => x.id && x.texto);
    const CHUNK = 25; // chunks chicos (cierre 31): con ~100 videos el JSON de juicio excede max_tokens → parse falla → fail-open dejaría pasar TODO sin score
    for (let ci = 0; ci < lote.length; ci += CHUNK) {
      const sub = lote.slice(ci, ci + CHUNK);
      if (!first) await sleep(SLEEP_MS); first = false;
      const sys = 'Sos un jurado ESTRICTO de relevancia y calidad. Te doy el tema de un proyecto, sus criterios (el TEMA manda; el AJUSTE DE VOZ solo complementa), y una lista de videos (id + transcript). Para cada uno decidi si es RELEVANTE y UTIL segun los criterios. Precision: ante la duda, marca relevante:false. Devolve UNICAMENTE un JSON {"juicio":[{"id":"...","relevante":true,"score":0.0,"razon":"breve"}]}. score 0..1 = que tan bien cumple los criterios.';
      const usr = 'TEMA: ' + (p.nombre || '') + '\n' + criteriosTxt + '\n\nVIDEOS:\n' + JSON.stringify(sub);
      try {
        const resp = await this.helpers.httpRequest({
          method: 'POST', url: 'https://api.anthropic.com/v1/messages',
          headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
          body: { model: 'claude-haiku-4-5', max_tokens: 4000, system: sys, messages: [{ role: 'user', content: usr }] },
          json: true, timeout: 60000
        });
        let txt = '';
        try { txt = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
        const m = String(txt).match(/\{[\s\S]*\}/);
        if (m) { const parsed = JSON.parse(m[0]); (parsed.juicio || []).forEach(j => { juicio[String(j.id)] = j; }); }
      } catch (e) { /* fail-open por chunk: estos videos pasan sin juicio, ordenan por métrica */ }
    }
  }
  const kept = arr.filter(d => { const j = juicio[String(d.external_id)]; if (j && j.relevante === false) return false; const sc = j && typeof j.score === 'number' ? j.score : null; if (sc != null && sc < MIN_REL) return false; return true; });
  arr.forEach(d => { if (kept.indexOf(d) >= 0) return; const j = juicio[String(d.external_id)]; const motivo = j ? (j.relevante === false ? 'irrelevante' : 'score<min') : 'sin-juicio'; console.log('[Gate] DESCARTE pid=' + pid + ' id=' + d.external_id + ' score=' + (j && j.score != null ? j.score : 'n/a') + ' motivo=' + motivo + (j && j.razon ? ' :: ' + j.razon : ''));
    const sc = j && typeof j.score === 'number' ? j.score : null;
    if (sc != null) _borderline.push({ d, score: sc, razon: (j && j.razon) || '' });
  });
  const prescores = kept.map(d => Number(d.heat_score || 0));
  kept.forEach(d => {
    const j = juicio[String(d.external_id)];
    const sHaiku = j && typeof j.score === 'number' ? Math.max(0, Math.min(1, j.score)) : null;
    const metricPct = pct(prescores, Number(d.heat_score || 0));
    const composite = sHaiku != null ? (PESO * sHaiku + (1 - PESO) * metricPct) : metricPct;
    const sinScript = !String(d.script || '').trim();
    const razonBase = (j && j.razon) || '';
    const razon = sinScript ? ('[SIN TRANSCRIPT: juzgado por caption, revisar manual] ' + razonBase).trim() : razonBase;
    out.push({ json: Object.assign({}, d, {
      prescore_metrico: Number(d.heat_score || 0),
      relevancia_score: sHaiku,
      relevancia_razon: razon,
      heat_score: Math.round(composite * 10000) / 10000
    }) });
  });
}
// Emite los TOP-K rechazos por score marcados _descarte (cap global por corrida, mejores primero):
// Armar candidato los ignora; Preparar batch Descartes los sube al cockpit (ADR-021).
_borderline.sort((a, b) => b.score - a.score);
for (const b of _borderline.slice(0, Math.max(0, CAP_DESC))) {
  out.push({ json: Object.assign({}, b.d, { _descarte: true, relevancia_score: b.score, relevancia_razon: b.razon }) });
}
if (_borderline.length) console.log('[Gate] descartes top-K expuestos: ' + Math.min(_borderline.length, Math.max(0, CAP_DESC)) + '/' + _borderline.length);
return out;

// Corte final POR PROYECTO (ADR-024, enmienda del corte global de ADR-016) + piso ADR-017 + dedup ADR-018.
// ORDEN (importa): 1) dedup — una copia por video (ADR-018) => cada video queda en UN solo proyecto;
// 2) recien ahi cada proyecto corta a SU N por heat compuesto. Al reves (cortar y despues dedupear,
// como hacia ADR-016) dos proyectos que pescan el mismo video colisionan y los DOS quedan cortos: N
// seria un techo, no una entrega. Con este orden N se cumple exacto.
// cap_top_n NO se toca: es el techo duro de transcripcion y ya mordio antes, en Heat-score v1.
const _plan = $('Armar plan de corrida').first().json || {};
const _projects = _plan.projects || {};
const N_DEF = Number(_plan.top_n || $('Config').first().json.top_n || 100);
const _nDe = (pid) => { const p = _projects[pid]; const n = Number(p && p.n); return n > 0 ? n : N_DEF; };
const _all = $input.all().filter(i => !i.json._descarte).slice().sort( // los _descarte van al cockpit por su propia rama (ADR-021)
(a, b) => (Number(b.json.heat_score || 0)) - (Number(a.json.heat_score || 0)));
const PISO = Number($('Config').first().json.piso_referente || 0); // piso leve por cuenta fuente (ADR-017): evita que un referente acapare el corte.

// 1) DEDUP (ADR-018, enmienda ADR-013): del fan-out gana la copia de mayor relevancia_score (empate:
// heat) => el video se lo lleva el proyecto que lo juzgo mas relevante. Items sin id se conservan.
const _rs = (x) => (x.json.relevancia_score != null ? Number(x.json.relevancia_score) : -1);
const _best = {};
const _sinId = [];
for (const it of _all) {
  const id = String(it.json.external_id || '');
  if (!id) { _sinId.push(it); continue; }
  const prev = _best[id];
  if (!prev || _rs(it) > _rs(prev) || (_rs(it) === _rs(prev) && Number(it.json.heat_score || 0) > Number(prev.json.heat_score || 0))) _best[id] = it;
}

// 2) CORTE POR PROYECTO: cada proyecto ordena sus ganadores por heat y corta a su N (PISO primero).
const _porProy = {};
for (const id in _best) { const it = _best[id]; const pid = String(it.json.proyecto_id || ''); (_porProy[pid] = _porProy[pid] || []).push(it); }
const _keep = new Set(_sinId);
for (const pid in _porProy) {
  const arr = _porProy[pid].sort((a, b) => (Number(b.json.heat_score || 0)) - (Number(a.json.heat_score || 0)));
  const N = _nDe(pid);
  const _sel = new Set();
  // PISO: round-robin por cuenta fuente, hasta PISO videos por cuenta, sin pasar de N.
  if (PISO > 0) {
    const _byUser = {};
    arr.forEach(it => { const u = String(it.json.username || '').toLowerCase(); (_byUser[u] = _byUser[u] || []).push(it); });
    const _users = Object.keys(_byUser);
    for (let r = 0; r < PISO && _sel.size < N; r++) { for (const u of _users) { if (_sel.size >= N) break; const a = _byUser[u]; if (r < a.length) _sel.add(a[r]); } }
  }
  // FILL: completar por heat hasta N.
  for (const it of arr) { if (_sel.size >= N) break; _sel.add(it); }
  _sel.forEach(it => _keep.add(it));
  console.log('[Corte] proyecto=' + ((_projects[pid] || {}).nombre || pid || 'sin proyecto') + ' N=' + N + ' disponibles=' + arr.length + ' entregados=' + _sel.size);
}

// Normaliza idioma al set canónico del cockpit {es,en,pt,it,fr,otro} — evita opciones basura en el single-select de Airtable (ej: 'ingles','ru','ot' que devolvían Supadata/Haiku).
const _CANON = new Set(['es', 'en', 'pt', 'it', 'fr']);
const _LANG_WORD = { ingles: 'en', english: 'en', espanol: 'es', spanish: 'es', castellano: 'es', portugues: 'pt', portuguese: 'pt', italiano: 'it', italian: 'it', frances: 'fr', french: 'fr' };
const normLang = (v) => { let s = String(v || '').toLowerCase().trim(); if (!s) return ''; if (_LANG_WORD[s]) return _LANG_WORD[s]; s = s.slice(0, 2); return _CANON.has(s) ? s : 'otro'; };
const out = [];
for (const it of _all) {
  if (!_keep.has(it)) continue;
  const d = it.json;
  const _tituloBase = String(d.descripcion || '').replace(/\s+/g, ' ').trim().slice(0, 80) || (d.username || 'video');
  // Decisión #6 (2026-07-09): sin transcript pasa igual (fail-open) pero con marca visible en el feed.
  const titulo = (String(d.script || '').trim() ? '' : '⚠️ SIN GUION | ') + _tituloBase;
  out.push({ json: {
    titulo,
    script: String(d.script || '').slice(0, 95000),
    idioma: normLang(d.idioma || d.idioma_detectado),
    proyecto_id: d.proyecto_id || null, proyecto_nombre: d.proyecto_nombre || '',
    voz_id: d.voz_id || null, voz_nombre: d.voz_nombre || '',
    referente: d.username || '', url_referente: d.url || '',
    views: Number(d.reproducciones || 0), likes: Number(d.likes || 0),
    seguidores: Number(d.seguidores || 0), engagement: parseFloat(d.engagement_rate) || 0,
    heat_score: Number(d.heat_score || 0), viral_por_tamano: !!d.viral_por_tamano,
    plataforma: d.plataforma || '', external_id: String(d.external_id || ''),
    relevancia_score: (d.relevancia_score != null ? d.relevancia_score : null),
    relevancia_razon: d.relevancia_razon || '', thumbnail_url: d.thumbnail_url || ''
  } });
}
return out;

