// Resumen del run (ADR-021) — arma runs.metricas: embudo + sin_guion + llamadas estimadas por
// servicio + desglose por referente (evaluados/gate_pass en videos DISTINTOS; habilita la higiene
// de fuentes de ADR-022). Cerrar run persiste $json.metricas tal cual.
const gateAll = $('Gate de relevancia').all();
const gateKept = gateAll.filter(i => !i.json._descarte);
const outputs = $('Armar candidato').all();
const gateIn = $('Traducir (Claude Haiku)').all();
const _distinct = (items) => new Set(items.map(i => String(i.json.external_id || '')).filter(Boolean)).size;
const _lotes = (items) => new Set(items.map(i => String(i.json.proyecto_id || '')).filter(Boolean)).size;
// llamadas estimadas: Supadata = videos distintos transcritos (dedup intra-corrida, ADR-016);
// Haiku: pre-trim = 1 lote/proyecto (cota superior: exentos/sin-criterios no llaman), gate = chunks
// de a 25 por proyecto (cierre 31), traducciones = videos DISTINTOS no-ES (Traducir dedupea, cierre 31).
const _lotesChunk = (items, chunk) => { const by = {}; items.forEach(i => { const p = String(i.json.proyecto_id || ''); if (p) by[p] = (by[p] || 0) + 1; }); return Object.values(by).reduce((a, n) => a + Math.ceil(n / chunk), 0); };
const llamadas = {
  supadata: _distinct($('Transcribir (Supadata)').all()),
  haiku_lotes_pretrim: _lotes($('Asignar proyecto+voz').all()),
  haiku_lotes_gate: _lotesChunk(gateIn, 25),
  haiku_traducciones: new Set(gateIn.filter(i => String(i.json.transcripcion || '').trim() && (i.json.idioma || 'es') !== 'es').map(i => String(i.json.external_id || i.json.url || '')).filter(Boolean)).size
};
const por_referente = {};
const _mark = (items, key) => { const seen = new Set(); for (const it of items) { const u = String(it.json.username || '').toLowerCase(); const id = String(it.json.external_id || ''); if (!u || !id) continue; const k = u + '|' + id; if (seen.has(k)) continue; seen.add(k); (por_referente[u] = por_referente[u] || { evaluados: 0, gate_pass: 0 })[key]++; } };
_mark(gateIn, 'evaluados');
_mark(gateKept, 'gate_pass');
const _n = (name) => { try { return $(name).all().length; } catch (e) { return 0; } };
const metricas = {
  colectados: $('Merge scrapes').all().length,
  apify_ig: _n('Apify — IG Reels'),
  apify_tt: _n('Apify — TikTok Perfil'),
  asignados: $('Asignar proyecto+voz').all().length,
  pretrim: $('Pre-trim relevancia').all().length,
  filtrados: $('Heat-score v1').all().length,
  gate: gateKept.length,
  outputs: outputs.length,
  sin_guion: outputs.filter(i => !String(i.json.script || '').trim()).length,
  descartes_expuestos: gateAll.length - gateKept.length,
  llamadas, por_referente
};
console.log('[Resumen] ' + JSON.stringify(metricas));
return [{ json: { metricas } }];
